 private LinearLayout page(){LinearLayout b=vert();b.setPadding(dp(16),dp(18),dp(16),dp(24));b.setBackgroundColor(BG);ScrollView s=new ScrollView(this);s.setFillViewport(true);s.addView(b);content.removeAllViews();content.addView(s);return b;}
