 private LinearLayout title(String s,String action){LinearLayout r=horiz();r.addView(tv(s,22,DARK,true),new LinearLayout.LayoutParams(0,dp(48),1));if(action!=null){TextView a=tv(action,14,BLUE,true);a.setGravity(Gravity.RIGHT|Gravity.CENTER_VERTICAL);r.addView(a,new LinearLayout.LayoutParams(-2,dp(48)));}return r;}
