 private void formatMoney(EditText e){e.addTextChangedListener(new TextWatcher(){boolean lock;public void beforeTextChanged(CharSequence s,int a,int b,int c){}public void onTextChanged(CharSequence s,int a,int b,int c){}public void afterTextChanged(Editable x){if(lock)return;lock=true;long n=parse(x.toString());e.setText(n==0?"":NumberFormat.getNumberInstance(VI).format(n));e.setSelection(e.length());lock=false;}});}
